sql:
SELECT number_of_employees
FROM workforce
WHERE competitor_id = 0;

SELECT MAX(number_of_employees) AS max_employees
FROM workforce
WHERE year = 2022;

SELECT competitor_name
FROM competitors
WHERE last_updated = (SELECT MAX(last_updated) FROM competitors);

SELECT year, AVG(number_of_employees) AS avg_employees
FROM workforce
GROUP BY year;

external_knowledge:
- 'reached a giant status' refers to having a valuation greater than $100,000,000; 
- 'on a rocket ship' refers to having an employee growth rate greater than 20%;
- 'most recent workforce years' refers to years within the last two years (calculated based on the maximum year in the workforce table).

- 'Major competitor' refers to a competitor who has more than one entry in the workforce and financials data within the specified years; 
- 'Active for multiple years' implies the competitor has workforce and financial data for more than one year between 2020 and 2022; 
- 'Revenue of over $50 million' is based on the maximum revenue achieved by the competitor in any of the specified years.

- "Globally established" refers to companies with a geo_presence of 'Global'; 
- "Analysts" are a specific user role; 
- "Workforce growth" is measured by the 'employee_growth' column; 
- "Viewed more than once" refers to having more than one distinct 'access_id'.

sql:
SELECT w.avg_salary, 'analyst' AS role
FROM workforce w
WHERE w.year = 2022 AND w.competitor_id = 0;
